-- ============================================================
-- SCRIPT DE REPARACIÓN FLYWAY — EJECUTAR ANTES DEL PRIMER DEPLOY
-- ============================================================
-- Problema: La BD de producción tiene Flyway solo hasta V9.
-- Las migraciones V10-V67 nunca se registraron en flyway_schema_history
-- porque el schema se creó via ddl-auto=update (Hibernate).
-- 
-- Sin este script, el deploy fallará al intentar aplicar V10-V67
-- sobre tablas/columnas que ya existen.
--
-- Solución: Registrar V10-V67 como "ya aplicadas" con sus checksums
-- correctos (calculados con Flyway en BD limpia el 2026-06-17).
-- Flyway verá el historial completo y saltará directamente a V68+V69.
--
-- CÓMO EJECUTAR EN RAILWAY:
--   1. Conectarse a la BD de producción (Railway Dashboard → Connect)
--   2. Ejecutar este script completo
--   3. Verificar: SELECT version FROM flyway_schema_history ORDER BY installed_rank DESC LIMIT 5;
--   4. Hacer el deploy normal
-- ============================================================


-- ============================================================
-- VERIFICACIÓN POST-EJECUCIÓN
-- ============================================================
SELECT version, description, success 
FROM flyway_schema_history 
ORDER BY CAST(version AS UNSIGNED);
-- Debe mostrar V1 hasta V67 (57 filas), todas con success=1
-- Después del deploy se agregarán V68 y V69 automáticamente
